import axios from "axios";
const apiURL = process.env.REACT_APP_API_URL;

export const cartListProduct = async () => {
  let carts = JSON.parse(localStorage.getItem("cart"));
  let productArray = [];
  if (carts) {
    for (const cart of carts) {
      productArray.push(cart.id);
    }
  }
  try {
    let res = await axios.post(`${apiURL}/api/product/cart-product`, {
      productArray,
    });
    return res.data;
  } catch (error) {
    console.log(error);
  }
};
export const getUserNotifications = async () => {
  try {
    const userData = JSON.parse(localStorage.getItem("jwt"));
    const userId = userData.user._id;

    const res = await fetch(
      `http://localhost:8000/api/user-notifications/${userId}`
    );

    return await res.json();
  } catch (err) {
    console.log("Get Notifications Frontend Error:", err);
  }
};

export const markNotificationRead = async (id) => {
  try {
    const res = await fetch(
      `http://localhost:8000/api/mark-notification-read/${id}`,
      {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
        },
      }
    );

    return await res.json();
  } catch (err) {
    console.log("Mark Notification Read Frontend Error:", err);
  }
};
